INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1\", \"count\": 3, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-23 07:42:10', 0.021, NULL, NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (21, 43, '四级手术与三级手术患者死亡率比', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"分子结果：1 条记录。\"}, {\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"分母结果：1 条记录。\"}, {\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"执行完成。指标值：100.0%（1/1）\"}]', 'SELECT \n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \n    / \n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g4_death_rate\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \n    AND h.INHOS_NO = o.INHOS_NO\nWHERE o.OPRT_LVL_CD = \'4\'\n  AND h.DSCG_DT_TM IS NOT NULL\n  AND h.INVLD_FLG = \'0\' \n  AND o.INVLD_FLG = \'0\';', 'SELECT \n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \n    / \n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g3_death_rate\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \n    AND h.INHOS_NO = o.INHOS_NO\nWHERE o.OPRT_LVL_CD = \'3\'\n  AND h.DSCG_DT_TM IS NOT NULL\n  AND h.INVLD_FLG = \'0\' \n  AND o.INVLD_FLG = \'0\';', '', 1, 1, 100, '1/1=100.0%', '', '{\"rows\": [], \"columns\": []}', '{}', '', '', '', '[{\"sql\": \"SELECT \\n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \\n    / \\n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g4_death_rate\\nFROM FACT_MDC_RCD_HMPG h\\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \\n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \\n    AND h.INHOS_NO = o.INHOS_NO\\nWHERE o.OPRT_LVL_CD = \'4\'\\n  AND h.DSCG_DT_TM IS NOT NULL\\n  AND h.INVLD_FLG = \'0\' \\n  AND o.INVLD_FLG = \'0\';\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', 