INSERT INTO `indicator_execution` VALUES (34, 62, '住院手术患者VTE发生率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"02:44:39\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"02:44:39\", \"level\": \"info\", \"message\": \"分子结果：2 条记录。\"}, {\"time\": \"02:44:39\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"02:44:39\", \"level\": \"info\", \"message\": \"分母结果：12 条记录。\"}, {\"time\": \"02:44:39\", \"level\": \"info\", \"message\": \"执行完成。指标值：16.6667%（2/12）\"}]', 'SELECT DISTINCT t1.INHOS_NO\nFROM FACT_MDC_RCD_HMPG t1\nWHERE t1.INVLD_FLG = \'0\'\nAND EXISTS (\n    SELECT 1\n    FROM FACT_MDC_RCD_HMPG_OPRT t2\n    WHERE t1.INHOS_NO = t2.INHOS_NO\n      AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\n      AND t2.INVLD_FLG = \'0\'\n)\nAND EXISTS (\n    SELECT 1\n    FROM FACT_MDC_RCD_HMPG_DIAG t3\n    WHERE t1.INHOS_NO = t3.INHOS_NO\n      AND t1.MDC_ORG_CD = t3.MDC_ORG_CD\n      AND t3.INVLD_FLG = \'0\'\n      AND (\n          t3.DIAG_NM LIKE \'深静脉血栓形成\'\n          OR t3.DIAG_NM LIKE \'肺动脉栓塞\'\n      )\n      AND t3.INHOS_CDT_CD = \'4\'\n)', 'SELECT DISTINCT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM\nFROM FACT_MDC_RCD_HMPG t1 \nJOIN FACT_MDC_RCD_HMPG_OPRT t2 \nON t1.INHOS_NO = t2.INHOS_NO AND t1.MDC_ORG_CD = t2.MDC_ORG_CD \nWHERE t1.INVLD_FLG = \'0\' AND t2.INVLD_FLG = \'0\'', '', 2, 12, 16.6667, '2/12=16.6667%', '', '{\"rows\": [{\"INHOS_NO\": \"INH_20260405_004\"}, {\"INHOS_NO\": \"INH_20260405_015\"}], \"columns\": [\"INHOS_NO\"]}', '{\"rows\": [{\"NM\": \"赵六\", \"INHOS_NO\": \"INH_20260405_004\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"郑十\", \"INHOS_NO\": \"INH_20260405_008\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"陈十一\", \"INHOS_NO\": \"INH_20260405_011\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"林十二\", \"INHOS_NO\": \"INH_20260405_012\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"黄十三\", \"INHOS_NO\": \"INH_20260405_013\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"周十四\", \"INHOS_NO\": \"INH_20260405_014\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"吴十五\", \"INHOS_NO\": \"INH_20260405_015\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"郑十六\", \"INHOS_NO\": \"INH_20260405_016\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"刘十七\", \"INHOS_NO\": \"INH_20260405_017\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"何十八\", \"INHOS_NO\": \"INH_20260405_018\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"黄二十二\", \"INHOS_NO\": \"INH_20260405_022\", \"MDC_ORG_CD\": \"HOS_001\"}, {\"NM\": \"马二十九\", \"INHOS_NO\": \"INH_20260405_029\", \"MDC_ORG_CD\": \"HOS_001\"}], \"columns\": [\"INHOS_NO\", \"MDC_ORG_CD\", \"NM\"]}', '', '', '', '[{\"sql\": \"SELECT DISTINCT t1.INHOS_NO\\nFROM FACT_MDC_RCD_HMPG t1\\nWHERE t1.INVLD_FLG = \'0\'\\nAND EXISTS (\\n    SELECT 1\\n    FROM FACT_MDC_RCD_HMPG_OPRT t2\\n    WHERE t1.INHOS_NO = t2.INHOS_NO\\n      AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\\n      AND t2.INVLD_FLG = \'0\'\\n)\\nAND EXISTS (\\n    SELECT 1\\n    FROM FACT_MDC_RCD_HMPG_DIAG t3\\n    WHERE t1.INHOS_NO = t3.INHOS_NO\\n      AND t1.MDC_ORG_CD = t3.MDC_ORG_CD\\n      AND t3.INVLD_FLG = \'0\'\\n      AND (\\n          t3.DIAG_NM LIKE \'深静脉血栓形成\'\\n          OR t3.DIAG_NM LIKE \'肺动脉栓塞\'\\n      )\\n      AND t3.INHOS_CDT_CD = \'4\'\\n)\", \"count\": 2, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-28 02:44:39', 0.085, NULL, NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (35, 56, '患者住院、新生儿、手术患者住院总死亡率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"06:23:12\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"06:23:12\", \"level\": \"error\", \"message\": \"执行失败：(1064, \\\"You have an error in your SQL syntax; check the manual that corresponds to your MySQL server version for the right syntax to use near \'SELECT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM, t1.DSCG_DT_TM, t1.DSCG_WAY_NM, t1.TNOV\' at line 5\\\")\"}]', '', '', '-- 分子\nSELECT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM, t1.DSCG_DT_TM, t1.DSCG_WAY_NM, t1.TNOVR_CDT_NM FROM FACT_MDC_RCD_HMPG AS t1 WHERE t1.INVLD_FLG = \'0\' AND t1.DSCG_DT_TM IS NOT NULL AND (t1.DSCG_WAY_NM LIKE \'%死亡%\' OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM LIKE \'%非医嘱离院%\'))\n\n-- 分母\nSELECT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM, t1.DSCG_DT_TM, t1.DSCG_WAY_NM, t1.TNOVR_CDT_NM FROM FACT_MDC_RCD_HMPG AS t1 WHERE t1.INVLD_FLG = \'0\' AND t1.DSCG_DT_TM IS NOT NULL', NULL, NULL, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '(1064, \"You have an error in your SQL syntax; check the manual that corresponds to your MySQL server version for the right syntax to use near \'SELECT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM, t1.DSCG_DT_TM, t1.DSCG_WAY_NM, t1.TNOV\' at line 5\")', '', '', '[{\"sql\": \"-- 分子\\nSELECT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM, t1.DSCG_DT_TM, t1.DSCG_WAY_NM, t1.TNOVR_CDT_NM FROM FACT_MDC_RCD_HMPG AS t1 WHERE t1.INVLD_FLG = \'0\' AND t1.DSCG_DT_TM IS NOT NULL AND (t1.DSCG_WAY_NM LIKE \'%死亡%\' OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM LIKE \'%非医嘱离院%\'))\\n\\n-- 分母\\nSELECT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM, t1.DSCG_DT_TM, t1.DSCG_WAY_NM, t1.TNOVR_CDT_NM FROM FACT_MDC_RCD_HMPG AS t1 WHERE t1.INVLD_FLG = \'0\' AND t1.DSCG_DT_TM IS NOT NULL\", \"count\": 0, \"error\": \"(1064, \\\"You have an error in your SQL syntax; check the manual that corresponds to your MySQL server version for the right syntax to use near \'SELECT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM, t1.DSCG_DT_TM, t1.DSCG_WAY_NM, t1.TNOV\' at line 5\\\")\", \"attempt\": 1}]', '', '', 0, '', '', 'failed', '2026-04-28 06:23:12', 0.246, NULL, NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (36, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"08:12:40\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"08:12:40\", \"level\": \"info\", \"message\": \"查询结果：2 条记录。\"}, {\"time\": \"08:12:40\", \"level\": \"info\", \"message\": \"执行完成，共 2 条记录。\"}]', '', '', 'WITH \n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\nmain_diag_sub AS (\n    SELECT \n        MDC_ORG_CD,\n        MDC_ORG_NM,\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\n        AND DIAG_CD IS NOT NULL\n        AND DIAG_CD != \'\'\n)\n-- 按医疗机构分组，统计不同亚目数量\nSELECT \n    MDC_ORG_CD AS \'医疗机构代码\',\n    MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\nFROM main_diag_sub\nWHERE sub_category IS NOT NULL \n    AND sub_category != \'\'\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\nORDER BY MDC_ORG_CD;', NULL, NULL, NULL, '', '', '{\"rows\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"WITH \\n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\\nmain_diag_sub AS (\\n    SELECT \\n        MDC_ORG_CD,\\n        MDC_ORG_NM,\\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\\n    FROM FACT_MDC_RCD_HMPG_DIAG\\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\\n        AND DIAG_CD IS NOT NULL\\n        AND DIAG_CD != \'\'\\n)\\n-- 按医疗机构分组，统计不同亚目数量\\nSELECT \\n    MDC_ORG_CD AS \'医疗机构代码\',\\n    MDC_ORG_NM AS \'医疗机构名称\',\\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\\nFROM main_diag_sub\\nWHERE sub_category IS NOT NULL \\n    AND sub_category != \'\'\\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\\nORDER BY MDC_ORG_CD;\", \"count\": 2, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-28 08:12:40', 0.457, NULL, NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (37, 52, '主要手术ICD-9-CM-3四位码种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"08:13:23\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"08:13:23\", \"level\": \"info\", \"message\": \"查询结果：1 条记录。\"}, {\"time\": \"08:13:23\", \"level\": \"info\", \"message\": \"执行完成，共 1 条记录。\"}]', '', '', 'WITH \nmain_surgery AS (\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\n    SELECT \n        s.INHOS_NO,\n        s.OPRT_CD,\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\n    FROM FACT_MDC_RCD_HMPG_OPRT s\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\n        AND s.OPRT_CD IS NOT NULL\n        AND s.OPRT_CD != \'\'\n)\nSELECT \n    h.MDC_ORG_CD AS \'医疗机构代码\',\n    h.MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\nFROM main_surgery ms\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\nWHERE ms.surgery_4code IS NOT NULL \n    AND ms.surgery_4code != \'\'\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\nORDER BY h.MDC_ORG_CD;', NULL, NULL, NULL, '', '', '{\"rows\": [{\"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\", \"手术四位码种类数\": 12}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"手术四位码种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"WITH \\nmain_surgery AS (\\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\\n    SELECT \\n        s.INHOS_NO,\\n        s.OPRT_CD,\\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\\n    FROM FACT_MDC_RCD_HMPG_OPRT s\\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\\n        AND s.OPRT_CD IS NOT NULL\\n        AND s.OPRT_CD != \'\'\\n)\\nSELECT \\n    h.MDC_ORG_CD AS \'医疗机构代码\',\\n    h.MDC_ORG_NM AS \'医疗机构名称\',\\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\\nFROM main_surgery ms\\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\\nWHERE ms.surgery_4code IS NOT NULL \\n    AND ms.surgery_4code != \'\'\\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\\nORDER BY h.MDC_ORG_CD;\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-28 08:13:23', 0.005, NULL, NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (38, 42, '四级手术与三级手术并发症发生率比', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"08:16:17\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"08:16:17\", \"level\": \"info\", \"message\": \"分子结果：1 条记录。\"}, {\"time\": \"08:16:17\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"08:16:17\", \"level\": \"info\", \"message\": \"分母结果：1 条记录。\"}, {\"time\": \"08:16:17\", \"level\": \"info\", \"message\": \"执行完成。指标值：100.0%（1/1）\"}]', 'WITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'4\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g4_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO', 'WITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'3\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g3_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO', '', 1, 1, 100, '1/1=100.0%', '', '{\"rows\": [{\"comp_cnt\": 0, \"total_cnt\": 0, \"g4_comp_rate\": 0.0}], \"columns\": [\"total_cnt\", \"comp_cnt\", \"g4_comp_rate\"]}', '{\"rows\": [{\"comp_cnt\": 0, \"total_cnt\": 1, \"g3_comp_rate\": 0.0}], \"columns\": [\"total_cnt\", \"comp_cnt\", \"g3_comp_rate\"]}', '', '', '', '[{\"sql\": \"WITH Target_Complications AS (\\n    SELECT DIAG_CD\\n    FROM FACT_MDC_RCD_HMPG_DIAG\\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\\n),\\nBase_Surgery_Patients AS (\\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\\n    FROM FACT_MDC_RCD_HMPG h\\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \\n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \\n        AND h.INHOS_NO = o.INHOS_NO\\n    WHERE o.OPRT_LVL_CD = \'4\'\\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\\n      AND h.DSCG_DT_TM IS NOT NULL\\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\\n),\\nComplication_Patients AS (\\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\\n    FROM FACT_MDC_RCD_HMPG_DIAG d\\n    INNER JOIN Target_Complications tc \\n        ON d.DIAG_CD = tc.DIAG_CD\\n    WHERE d.INVLD_FLG = \'0\' \\n      AND d.INHOS_CDT_CD != \'1\'\\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\\n)\\nSELECT \\n    COUNT(b.INHOS_NO) AS total_cnt,\\n    COUNT(c.INHOS_NO) AS comp_cnt,\\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \\n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \\n    END AS g4_comp_rate\\nFROM Base_Surgery_Patients b\\nLEFT JOIN Complication_Patients c \\n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \\n    AND b.INHOS_NO = c.INHOS_NO\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-28 08:16:17', 0.205, NULL, NULL, NULL, NULL, 0, NULL);
