ry != \'\'\\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\\nORDER BY MDC_ORG_CD;\", \"count\": 2, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-28 08:23:45', 0.004, NULL, NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (42, 52, '主要手术ICD-9-CM-3四位码种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"08:24:30\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"08:24:30\", \"level\": \"info\", \"message\": \"查询结果：1 条记录。\"}, {\"time\": \"08:24:30\", \"level\": \"info\", \"message\": \"执行完成，共 1 人次。\"}]', '', '', 'WITH \nmain_surgery AS (\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\n    SELECT \n        s.INHOS_NO,\n        s.OPRT_CD,\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\n    FROM FACT_MDC_RCD_HMPG_OPRT s\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\n        AND s.OPRT_CD IS NOT NULL\n        AND s.OPRT_CD != \'\'\n)\nSELECT \n    h.MDC_ORG_CD AS \'医疗机构代码\',\n    h.MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\nFROM main_surgery ms\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\nWHERE ms.surgery_4code IS NOT NULL \n    AND ms.surgery_4code != \'\'\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\nORDER BY h.MDC_ORG_CD;', NULL, NULL, NULL, '', '', '{\"rows\": [{\"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\", \"手术四位码种类数\": 12}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"手术四位码种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"WITH \\nmain_surgery AS (\\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\\n    SELECT \\n        s.INHOS_NO,\\n        s.OPRT_CD,\\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\\n    FROM FACT_MDC_RCD_HMPG_OPRT s\\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\\n        AND s.OPRT_CD IS NOT NULL\\n        AND s.OPRT_CD != \'\'\\n)\\nSELECT \\n    h.MDC_ORG_CD AS \'医疗机构代码\',\\n    h.MDC_ORG_NM AS \'医疗机构名称\',\\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\\nFROM main_surgery ms\\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\\nWHERE ms.surgery_4code IS NOT NULL \\n    AND ms.surgery_4code != \'\'\\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\\nORDER BY h.MDC_ORG_CD;\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-28 08:24:30', 0.004, NULL, NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (50, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"11:33:06\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"11:33:06\", \"level\": \"info\", \"message\": \"查询结果：2 条记录。\"}, {\"time\": \"11:33:06\", \"level\": \"info\", \"message\": \"执行完成，共 2 人次。\"}]', '', '', 'WITH \n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\nmain_diag_sub AS (\n    SELECT \n        MDC_ORG_CD,\n        MDC_ORG_NM,\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\n        AND DIAG_CD IS NOT NULL\n        AND DIAG_CD != \'\'\n)\n-- 按医疗机构分组，统计不同亚目数量\nSELECT \n    MDC_ORG_CD AS \'医疗机构代码\',\n    MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\nFROM main_diag_sub\nWHERE sub_category IS NOT NULL \n    AND sub_category != \'\'\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\nORDER BY MDC_ORG_CD;', NULL, NULL, NULL, '', '', '{\"rows\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"WITH \\n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\\nmain_diag_sub AS (\\n    SELECT \\n        MDC_ORG_CD,\\n        MDC_ORG_NM,\\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\\n    FROM FACT_MDC_RCD_HMPG_DIAG\\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\\n        AND DIAG_CD IS NOT NULL\\n        AND DIAG_CD != \'\'\\n)\\n-- 按医疗机构分组，统计不同亚目数量\\nSELECT \\n    MDC_ORG_CD AS \'医疗机构代码\',\\n    MDC_ORG_NM AS \'医疗机构名称\',\\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\\nFROM main_diag_sub\\nWHERE sub_category IS NOT NULL \\n    AND sub_category != \'\'\\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\\nORDER BY MDC_ORG_CD;\", \"count\": 2, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-11 03:33:06', 0.168, NULL, NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (51, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"00:06:50\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"00:06:50\", \"level\": \"info\", \"message\": \"查询结果：2 条记录。\"}, {\"time\": \"00:06:50\", \"level\": \"info\", \"message\": \"执行完成，共 2 人次。\"}]', '', '', 'WITH \n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\nmain_diag_sub AS (\n    SELECT \n        MDC_ORG_CD,\n        MDC_ORG_NM,\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\n        AND DIAG_CD IS NOT NULL\n        AND DIAG_CD != \'\'\n)\n-- 按医疗机构分组，统计不同亚目数量\nSELECT \n    MDC_ORG_CD AS \'医疗机构代码\',\n    MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\nFROM main_diag_sub\nWHERE sub_category IS NOT NULL \n    AND sub_category != \'\'\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\nORDER BY MDC_ORG_CD;', NULL, NULL, NULL, '', '', '{\"rows\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"WITH \\n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\\nmain_diag_sub AS (\\n    SELECT \\n        MDC_ORG_CD,\\n        MDC_ORG_NM,\\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\\n    FROM FACT_MDC_RCD_HMPG_DIAG\\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\\n        AND DIAG_CD IS NOT NULL\\n        AND DIAG_CD != \'\'\\n)\\n-- 按医疗机构分组，统计不同亚目数量\\nSELECT \\n    MDC_ORG_CD AS \'医疗机构代码\',\\n    MDC_ORG_NM AS \'医疗机构名称\',\\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\\nFROM main_diag_sub\\nWHERE sub_category IS NOT NULL \\n    AND sub_category != \'\'\\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\\nORDER BY MDC_ORG_CD;\", \"count\": 2, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-14 13:42:23', 0.179, NULL, NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (52, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"13:35:27\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"13:35:27\", \"level\": \"info\", \"message\": \"分子结果：864 条记录。\"}, {\"time\": \"13:35:27\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"13:35:27\", \"level\": \"info\", \"message\": \"分母结果：9065 条记录。\"}, {\"time\": \"13:35:27\", \"level\": \"info\", \"message\": \"执行完成。指标值：9.5312%（864/9065）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM\nFROM (\n    SELECT\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\';', '', 864, 9065, 9.5312, '864/9065=9.5312%', '', '{\"rows\": [{\"PRM_KEY\": \"HMPG_20260405_14\", \"INHOS_NO\": \"INH_20260405_004\", \"ADMN_DT_TM\": \"2026-04-04 11:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-04 12:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_06\", \"INHOS_NO\": \"INH_20260405_006\", \"ADMN_DT_TM\": \"2026-04-01 13:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-01 14:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_08\", \"INHOS_NO\": \"INH_20260405_008\", \"ADMN_DT_TM\": \"2026-04-03 15:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-03 16:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_11\", \"INHOS_NO\": \"INH_20260405_011\", \"ADMN_DT_TM\": \"2026-04-05 08:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-05 12:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_17\", \"INHOS_NO\": \"INH_20260405_017\", \"ADMN_DT_TM\": \"2026-04-05 14:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-05 17:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_38\", \"INHOS_NO\": \"INH_20260405_038\", \"ADMN_DT_TM\": \"2026-04-04 11:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-04 15:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_89\", \"INHOS_NO\": \"INH_20260405_089\", \"ADMN_DT_TM\": \"2026-04-05 09:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-05 16:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_100\", \"INHOS_NO\": \"INH_20260405_100\", \"ADMN_DT_TM\": \"2026-04-03 10:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-03 17:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_1019\", \"INHOS_NO\": \"INH_20260405_101\", \"ADMN_DT_TM\": \"2026-04-01 08:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-01 15:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_1024\", \"INHOS_NO\": \"INH_20260405_102\", \"ADMN_DT_TM\": \"2026-04-01 10:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-01 12:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_1037\", \"INHOS_NO\": \"INH_20260405_103\", \"ADMN_DT_TM\": \"2026-04-01 10:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-01 12:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_1049\", \"INHOS_NO\": \"INH_20260405_104\", \"ADMN_DT_TM\": \"2026-04-03 15:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-03 15:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_1059\", \"INHOS_NO\": \"INH_20260405_105\", \"ADMN_DT_TM\": \"2026-04-01 08:00:00\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-01 08:15:00\"}, {\"PRM_KEY\": \"HMPG_20260405_1067\"