ull}, {\"住院号\": \"INH_20260405_033\", \"入院日期时间\": \"2026-04-02 11:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_034\", \"入院日期时间\": \"2026-04-03 08:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_035\", \"入院日期时间\": \"2026-04-02 10:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_036\", \"入院日期时间\": \"2026-04-04 17:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_037\", \"入院日期时间\": \"2026-04-02 17:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_038\", \"入院日期时间\": \"2026-04-03 11:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_039\", \"入院日期时间\": \"2026-04-03 10:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_040\", \"入院日期时间\": \"2026-04-03 16:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_041\", \"入院日期时间\": \"2026-04-04 09:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_042\", \"入院日期时间\": \"2026-04-05 09:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_043\", \"入院日期时间\": \"2026-04-02 09:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_044\", \"入院日期时间\": \"2026-04-05 14:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_045\", \"入院日期时间\": \"2026-04-01 10:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_046\", \"入院日期时间\": \"2026-04-03 09:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_047\", \"入院日期时间\": \"2026-04-01 09:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_048\", \"入院日期时间\": \"2026-04-05 12:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_049\", \"入院日期时间\": \"2026-04-01 15:30:00\", \"出院日期时间\": null}], \"columns\": [\"住院号\", \"入院日期时间\", \"出院日期时间\"]}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM\\nFROM (\\n    SELECT\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1\", \"count\": 864, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-14 13:42:23', 0.596, NULL, NULL, NULL, NULL, 0, NULL);
