{\"住院号\": \"INH_20260405_043\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-02 09:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_044\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-05 14:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_045\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-01 10:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_046\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-03 09:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_047\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-01 09:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_048\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-05 12:30:00\", \"出院日期时间\": null}, {\"住院号\": \"INH_20260405_049\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-01 15:30:00\", \"出院日期时间\": null}], \"columns\": [\"住院号\", \"机构代码\", \"机构名称\", \"入院日期时间\", \"出院日期时间\"]}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    MDC_ORG_CD,    \\n    MDC_ORG_NM,    \\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM\\nFROM (\\n    SELECT\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1;\", \"count\": 864, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-15 18:29:44', 0.713, '[]', NULL, NULL, NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (78, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"20:00:40\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"20:00:40\", \"level\": \"info\", \"message\": \"分子结果：0 条记录。\"}, {\"time\": \"20:00:40\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"20:00:40\", \"level\": \"info\", \"message\": \"分母执行出错：(1054, \\\"Unknown column \'FACT_ADMN_MDC_HTR_RCD.MDC_ORG_CD\' in \'where clause\'\\\")\"}, {\"time\": \"20:00:40\", \"level\": \"error\", \"message\": \"执行失败：(1054, \\\"Unknown column \'FACT_ADMN_MDC_HTR_RCD.MDC_ORG_CD\' in \'where clause\'\\\")\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM\nFROM (\n    SELECT\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1 AND MDC_ORG_CD IN (\'HOS_002\')', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\' AND FACT_ADMN_MDC_HTR_RCD.MDC_ORG_CD IN (\'HOS_002\')', '', 0, NULL, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '(1054, \"Unknown colum