}, {\"PRM_KEY\": \"HMPG_20260405_1705\", \"INHOS_NO\": \"INH_20260405_170\", \"ADMN_DT_TM\": \"2026-04-03 09:00:00\", \"DSCG_DT_TM\": \"2026-04-25 14:00:00\", \"MDC_ORG_CD\": \"HOS_001\", \"MDC_ORG_NM\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-03 09:15:00\"}], \"columns\": [\"PRM_KEY\", \"INHOS_NO\", \"MDC_ORG_CD\", \"MDC_ORG_NM\", \"ADMN_DT_TM\", \"ODR_OPN_DT_TM\", \"ODR_ITM_TP_NM\", \"DSCG_DT_TM\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    MDC_ORG_CD,    \\n    MDC_ORG_NM,    \\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM,\\n    DSCG_DT_TM\\nFROM (\\n    SELECT\\n        t1.DSCG_DT_TM,\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1 AND DATE(DSCG_DT_TM) BETWEEN \'2026-04-01\' AND \'2026-04-30\'\", \"count\": 623, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-16 00:19:45', 0.751, '[]', 'monthly', '2026-04', NULL, 0, NULL);
INSERT INTO `indicator_execution` VALUES (98, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'quarterly', '2026年一季度', 'ratio', 'SQL录入', '', '[{\"time\": \"00:21:43\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"00:21:43\", \"level\": \"info\", \"message\": \"分子结果：0 条记录。\"}, {\"time\": \"00:21:43\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"00:21:43\", \"level\": \"info\", \"message\": \"分母结果：0 条记录。\"}, {\"time\": \"00:21:43\", \"level\": \"info\", \"message\": \"执行完成。指标值：None%（0/0）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1 AND MDC_ORG_CD IN (\'HOS_002\') AND DATE(DSCG_DT_TM) BETWEEN \'2026-01-01\' AND \'2026-03-31\'', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\'  AND t1.MDC_ORG_CD IN (\'HOS_002\') AND DATE(DSCG_DT_TM) BETWEEN \'2026-01-01\' AND \'2026-03-31\'', '', 0, 0, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"SE