{\"住院号\": \"INH_20260517_000024\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-24 21:33:00\", \"出院日期时间\": \"2026-01-27 01:56:00\"}, {\"住院号\": \"INH_20260517_000025\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-01 09:45:00\", \"出院日期时间\": \"2026-03-10 14:16:00\"}, {\"住院号\": \"INH_20260517_000026\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-06 10:03:00\", \"出院日期时间\": \"2026-03-21 13:56:00\"}, {\"住院号\": \"INH_20260517_000027\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-05-15 14:03:00\", \"出院日期时间\": \"2026-05-22 20:03:00\"}, {\"住院号\": \"INH_20260517_000028\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-09 17:34:00\", \"出院日期时间\": \"2026-03-19 11:24:00\"}, {\"住院号\": \"INH_20260517_000029\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-28 18:31:00\", \"出院日期时间\": \"2026-03-05 01:19:00\"}, {\"住院号\": \"INH_20260517_000030\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-01-20 10:16:00\", \"出院日期时间\": \"2026-01-21 05:09:00\"}, {\"住院号\": \"INH_20260517_000031\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-21 10:50:00\", \"出院日期时间\": \"2026-03-07 19:28:00\"}, {\"住院号\": \"INH_20260517_000032\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-11 00:34:00\", \"出院日期时间\": \"2026-04-23 01:07:00\"}, {\"住院号\": \"INH_20260517_000033\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-01-26 03:48:00\", \"出院日期时间\": \"2026-02-05 17:47:00\"}, {\"住院号\": \"INH_20260517_000034\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2025-12-08 08:02:00\", \"出院日期时间\": \"2025-12-11 15:52:00\"}, {\"住院号\": \"INH_20260517_000035\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-07 04:14:00\", \"出院日期时间\": \"2026-04-18 15:14:00\"}, {\"住院号\": \"INH_20260517_000036\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-09 12:56:00\", \"出院日期时间\": \"2026-04-12 03:03:00\"}, {\"住院号\": \"INH_20260517_000037\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-01-02 15:02:00\", \"出院日期时间\": \"2026-01-05 21:48:00\"}, {\"住院号\": \"INH_20260517_000038\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2025-12-12 00:26:00\", \"出院日期时间\": \"2025-12-16 15:42:00\"}, {\"住院号\": \"INH_20260517_000039\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-11 06:10:00\", \"出院日期时间\": \"2026-03-12 18:42:00\"}], \"columns\": [\"住院号\", \"机构代码\", \"机构名称\", \"入院日期时间\", \"出院日期时间\"]}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    MDC_ORG_CD,    \\n    MDC_ORG_NM,    \\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM,\\n    DSCG_DT_TM\\nFROM (\\n    SELECT\\n        t1.DSCG_DT_TM,\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1;\", \"count\": 3, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-17 14:26:07', 6.259, '[]', NULL, NULL, 'discharge', 0, '[]');
INSERT INTO `indicator_execution` VALUES (147, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"14:26:06\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"14:26:06\", \"level\": \"info\", \"message\": \"分子结果：3 条记录。\"}, {\"time\": \"14:26:06\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"14:26:06\", \"level\": \"info\", \"message\": \"分母结果：10010 条记录。\"}, {\"time\": \"14:26:06\", \"level\": \"info\", \"message\": \"执行完成。指标值：0.03%（3/10010）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\';', '', 3, 10010, 0.03, '3/10010=0.03%', '', '{\"rows\": [{\"prm_key\": \"HMPG_20260405_04\", \"inhos_no\": \"INH_20260405_004\", \"admn_dt_tm\": \"2026-04-04 11:00:00\", \"dscg_dt_tm\": null, \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-04 12