INSERT INTO `indicator_execution` VALUES (176, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"00:24:36\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"00:24:37\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分子：3 条\"}, {\"time\": \"00:24:37\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分母：5047 条\"}, {\"time\": \"00:24:37\", \"level\": \"info\", \"message\": \"[海南省示范医院] 指标值：0.0594%\"}, {\"time\": \"00:24:37\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"00:24:38\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分子：0 条\"}, {\"time\": \"00:24:38\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分母：4963 条\"}, {\"time\": \"00:24:38\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 指标值：0.0%\"}, {\"time\": \"00:24:38\", \"level\": \"info\", \"message\": \"汇总执行完成。总体指标值：0.03%（3/10010）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\';', '', 3, 10010, 0.03, '3/10010=0.03%', '', '{\"rows\": [{\"prm_key\": \"HMPG_20260405_04\", \"inhos_no\": \"INH_20260405_004\", \"admn_dt_tm\": \"2026-04-04 11:00:00\", \"dscg_dt_tm\": null, \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-04 12:15:00\"}, {\"prm_key\": \"HMPG_20260405_06\", \"inhos_no\": \"INH_20260405_006\", \"admn_dt_tm\": \"2026-04-01 13:00:00\", \"dscg_dt_tm\": \"2026-04-06 14:00:00\", \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-01 14:15:00\"}, {\"prm_key\": \"HMPG_20260405_08\", \"inhos_no\": \"INH_20260405_008\", \"admn_dt_tm\": \"2026-04-03 15:00:00\", \"dscg_dt_tm\": null, \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-03 16:15:00\"}], \"columns\": [\"prm_key\", \"inhos_no\", \"mdc_org_cd\", \"mdc_org_nm\", \"admn_dt_tm\", \"ODR_OPN_DT_TM\", \"ODR_ITM_TP_NM\", \"dscg_dt_tm\"]}', '{\"rows\": [{\"住院号\": \"INH_20260405_001\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-01 08:30:00\", \"出院日期时间\": \"2026-04-05 10:00:00\"}, {\"住院号\": \"INH_20260405_002\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-02 09:30:00\", \"出院日期时间\": \"2026-04-04 14:00:00\"}, {\"住院号\": \"INH_20260405_003\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-03 10:30:00\", \"出院日期时间\": \"2026-04-08 09:00:00\"}, {\"住院号\": \"INH_20260405_004\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-04 11:30:00\", \"出院日期时间\": \"2026-04-10 16:00:00\"}, {\"住院号\": \"INH_20260405_005\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-05 12:30:00\", \"出院日期时间\": \"2026-04-06 11:00:00\"}, {\"住院号\": \"INH_20260405_006\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-01 13:30:00\", \"出院日期时间\": \"2026-04-07 10:00: