INSERT INTO `indicator_execution` VALUES (185, 10, '未成年人高危预警', 'manual', 'four', 'immediate', '全量', 'ratio', 'SQL录入', '审核范围：未成年人', '[{\"time\": \"14:31:30\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"14:31:30\", \"level\": \"info\", \"message\": \"查询结果：5 条记录。\"}, {\"time\": \"14:31:30\", \"level\": \"info\", \"message\": \"执行完成，共 5 人次。\"}]', '', '', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        -- 时间限制（用的月份）\n        AND SUBSTR(v.VST_DT_TM, 1, 7) = \'2026-04\' \n        /* \n        也可以用“日”来筛选\n        AND v.VST_DT_TM >= \'2026-04-01 00:00:00\'\n        AND v.VST_DT_TM <  \'2026-05-01 00:00:00\'\n        */\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \n        -- 年龄筛选\n        /*\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\n        */\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18  AND v.MDC_ORG_CD IN (\'HOS_001\')', NULL, NULL, NULL, '', '', '{\"rows\": [{\"年龄\": 13, \"出生日期\": \"2012-05-20 00:00:00\", \"就诊时间\": \"2026-04-01 09:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ultrasound\", \"挂号流水号\": \"RG_RISK_001\", \"门急诊编号\": \"MZ20260401001\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 7, \"出生日期\": \"2018-11-02 00:00:00\", \"就诊时间\": \"2026-04-03 10:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"A50.9\", \"诊断名称\": \"先天梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_003\", \"门急诊编号\": \"MZ20260403003\", \"就诊科室名称\": \"感染科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 11, \"出生日期\": \"2014-07-22 00:00:00\", \"就诊时间\": \"2026-04-08 08:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_005\", \"门急诊编号\": \"MZ20260408005\", \"就诊科室名称\": \"泌尿外科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 7, \"出生日期\": \"2019-02-14 00:00:00\", \"就诊时间\": \"2026-04-12 15:20:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_007\", \"门急诊编号\": \"MZ20260412007\", \"就诊科室名称\": \"儿科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 10, \"出生日期\": \"2015-09-09 00:00:00\", \"就诊时间\": \"2026-04-18 09:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_009\", \"门急诊编号\": \"MZ20260418009\", \"就诊科室名称\": \"泌尿外科\", \"患者去向名称\": \"回家\"}], \"columns\": [\"机构名称\", \"门急诊编号\", \"挂号流水号\", \"年龄\", \"年龄单位\", \"就诊时间\", \"就诊科室名称\", \"性别名称\", \"出生日期\", \"诊断代码\", \"诊断名称\", \"患者去向名称\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"SELECT v.MDC_ORG_NM AS 机构名称,\\n         v.OTPT_EMG_NO AS 门急诊编号,\\n         v.RGST_NO AS 挂号流水号,\\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\\n         \'岁\' AS 年龄单位,\\n         v.VST_DT_TM AS 就诊时间,\\n         v.VST_DPT_NM AS 就诊科室名称,\\n         v.GDR_NM AS 性别名称,\\n         v.BTH_DT AS 出生日期,\\n         d.DIAG_ICD10_CD AS 诊断代码,\\n         d.DIAG_ICD10_NM AS 诊断名称,\\n         v.PTT_WHRABT_NM AS 患者去向名称\\nFROM FACT_OTPT_VST_INFMT v\\nJOIN FACT_OTPT_DIAG_INFMT d\\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\\nWHERE (v.INVLD_FLG IS NULL\\n        OR v.INVLD_FLG != \'1\')\\n        AND (d.INVLD_FLG IS NULL\\n        OR d.INVLD_FLG != \'1\')\\n        AND v.BTH_DT IS NOT NULL\\n        AND v.VST_DT_TM IS NOT NULL\\n        -- 时间限制（用的月份）\\n        AND SUBSTR(v.VST_DT_TM, 1, 7) = \'2026-04\' \\n        /* \\n        也可以用“日”来筛选\\n        AND v.VST_DT_TM >= \'2026-04-01 00:00:00\'\\n        AND v.VST_DT_TM <  \'2026-05-01 00:00:00\'\\n        */\\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \\n        -- 年龄筛选\\n        /*\\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\\n        */\\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18  AND v.MDC_ORG_CD IN (\'HOS_001\')\", \"count\": 5, \"error\": null, \"attempt\": 1}]', '', '', 0, ''