INSERT INTO `indicator_execution` VALUES (193, 10, '未成年人高危预警', 'manual', 'four', 'immediate', '全量', 'count', 'SQL录入', '审核范围：未成年人', '[{\"time\": \"14:35:02\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"14:35:02\", \"level\": \"info\", \"message\": \"查询结果：10 条记录。\"}, {\"time\": \"14:35:02\", \"level\": \"info\", \"message\": \"执行完成，共 10 人次。\"}]', '', '', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        -- 时间限制（用的月份）\n        AND SUBSTR(v.VST_DT_TM, 1, 7) = \'2026-04\' \n        /* \n        也可以用“日”来筛选\n        AND v.VST_DT_TM >= \'2026-04-01 00:00:00\'\n        AND v.VST_DT_TM <  \'2026-05-01 00:00:00\'\n        */\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \n        -- 年龄筛选\n        /*\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\n        */\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18;', NULL, NULL, NULL, '', '', '{\"rows\": [{\"年龄\": 13, \"出生日期\": \"2012-05-20 00:00:00\", \"就诊时间\": \"2026-04-01 09:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ultrasound\", \"挂号流水号\": \"RG_RISK_001\", \"门急诊编号\": \"MZ20260401001\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 16, \"出生日期\": \"2009-08-15 00:00:00\", \"就诊时间\": \"2026-04-02 14:15:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z30.0\", \"诊断名称\": \"一般避孕咨询\", \"挂号流水号\": \"RG_RISK_002\", \"门急诊编号\": \"MZ20260402002\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 7, \"出生日期\": \"2018-11-02 00:00:00\", \"就诊时间\": \"2026-04-03 10:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"A50.9\", \"诊断名称\": \"先天梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_003\", \"门急诊编号\": \"MZ20260403003\", \"就诊科室名称\": \"感染科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 16, \"出生日期\": \"2010-03-10 00:00:00\", \"就诊时间\": \"2026-04-05 16:40:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_004\", \"门急诊编号\": \"MZ20260405004\", \"就诊科室名称\": \"呼吸内科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 11, \"出生日期\": \"2014-07-22 00:00:00\", \"就诊时间\": \"2026-04-08 08:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_005\", \"门急诊编号\": \"MZ20260408005\", \"就诊科室名称\": \"泌尿外科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 17, \"出生日期\": \"2008-12-01 00:00:00\", \"就诊时间\": \"2026-04-10 11:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A51.9\", \"诊断名称\": \"早期梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_006\", \"门急诊编号\": \"MZ20260410006\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 7, \"出生日期\": \"2019-02-14 00:00:00\", \"就诊时间\": \"2026-04-12 15:20:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_007\", \"门急诊编号\": \"MZ20260412007\", \"就诊科室名称\": \"儿科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 14, \"出生日期\": \"2011-06-30 00:00:00\", \"就诊时间\": \"2026-04-15 23:10:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_008\", \"门急诊编号\": \"MZ20260415008\", \"就诊科室名称\": \"急诊科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 10, \"出生日期\": \"2015-09-09 00:00:00\", \"就诊时间\": \"2026-04-18 09:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_009\", \"门急诊编号\": \"MZ20260418009\", \"就诊科室名称\": \"泌尿外科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 13, \"出生日期\": \"2013-01-25 00:00:00\", \"就诊时间\": \"2026-04-20 13:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ultrasound\", \"挂号流水号\": \"RG_RISK_010\", \"门急诊编号\": \"MZ20260420010\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}], \"columns\": [\"机构名称\", \"门急诊编号\", \"挂号流水号\", \"年龄\", \"年龄单位\", \"就诊时间\", \"就诊科室名称\", \"性别名称\", \"出生日期\", \"诊断代码\", \"诊断名称\", \"患者去向名称\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"SELECT v.MDC_ORG_NM AS 机构名称,\\n         v.OTPT_EMG_NO AS 门急诊编号,\\n         v.RGST_NO AS 挂号流水号,\\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\\n         \'岁\' AS 年龄单位,\\n         v.VST_DT_TM AS 就诊时间,\\n         v.VST_DPT_NM AS 就诊科室名称,\\n         v.GDR_NM AS 性别名称,\\n         v.BTH_DT AS 出生日期,\\n         d.DIAG_ICD10_CD AS 诊断代码,\\n         d.DIAG_ICD10_NM AS 诊断名称,\\n         v.PTT_WHRABT_NM AS 患者去向名称\\nFROM FACT_OTPT_VST_INFMT v\\nJOIN FACT_OTPT_DIAG_INFMT d\\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\\nWHERE (v.INVLD_FLG IS NULL\\n        OR v.INVLD_FLG != \'1\')\\n        AND (d.INVLD_FLG IS NULL\\n        OR d.INVLD_FLG != \'1\')\\n        AND v.BTH_DT IS NOT NULL\\n        AND v.VST_DT_TM IS NOT NULL\\n        -- 时间限制（用的月份）\\n        AND SUBSTR(v.VST_DT_TM, 1, 7) = \'2026-04\' \\n        /* \\n        也可以用“日”来筛选\\n        AND v.VST_DT_TM >= \'2026-04-01 00:00:00\'\\n        AND v.VST_DT_TM <  \'2026-05-01 00:00:00\'\\n        */\\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \\n        -- 年龄筛选\\n        /*\\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\\n        */\\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18;\", \"count\": 10, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-18 14:35:02', 0.981, '[]', NULL, NULL, 'discharge', 0, '[]');
INSERT INTO `indicator_execution` VALUES (194, 10, '未成年人高危预警', 'manual', 'four', 'immediate', '全量', 'count', 'SQL录入', '审核范围：未成年人', '[{\"time\": \"14:42:40\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"14:42:40\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分子：5 条\"}, {\"time\": \"14:42:40\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分母：None 条\"}, {\"time\": \"14:42:40\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"14:42:40\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分子：5 条\"}, {\"time\": \"14:42:40\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分母：None 条\"}, {\"time\": \"14:42:40\", \"level\": \"info\", \"message\": \"汇总执行完成。总体指标值：None%（10/0）\"}]', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        -- 时间限制（用的月份）\n        AND SUBSTR(v.VST_DT_TM, 1, 7) = \'2026-04\' \n        /* \n        也可以用“日”来筛选\n        AND v.VST_DT_TM >= \'2026-04-01 00:00:00\'\n        AND v.VST_DT_TM <  \'2026-05-01 00:00:00\'\n        */\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \n        -- 年龄筛选\n        /*\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\n        */\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18;', '', '', 10, 0, NULL, '', '', '{\"rows\": [{\"年龄\": 16, \"出生日期\": \"2009-08-15 00:00:00\", \"就诊时间\": \"2026-04-02 14:15:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z30.0\", \"诊断名称\": \"一般避孕咨询\", \"挂号流水号\": \"RG_RISK_002\", \"门急诊编号\": \"MZ20260402002\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 16, \"出生日期\": \"2010-03-10 00:00:00\", \"就诊时间\": \"2026-04-05 16:40:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_004\", \"门急诊编号\": \"MZ20260405004\", \"就诊科室名称\": \"呼吸内科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 17, \"出生日期\": \"2008-12-01 00:00:00\", \"就诊时间\": \"2026-04-10 11:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A51.9\", \"诊断名称\": \"早期梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_006\", \"门急诊编号\": \"MZ20260410006\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 14, \"出生日期\": \"2011-06-30 00:00:00\", \"就诊时间\": \"2026-04-15 23:10:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_008\", \"门急诊编号\": \"MZ20260415008\", \"就诊科室名称\": \"急诊科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 13, \"出生日期\": \"2013-01-25 00:00:00\", \"就诊时间\": \"2026-04-20 13:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ultrasound\", \"挂号流水号\": \"RG_RISK_010\", \"门急诊编号\": \"MZ20260420010\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}], \"columns\": [\"机构名称\", \"门急诊编号\", \"挂号流水号\", \"年龄\", \"年龄单位\", \"就诊时间\", \"就诊科室名称\", \"性别名称\", \"出生日期\", \"诊断代码\", \"诊断名称\", \"患者去向名称\"]}', '{\"rows\": [], \"columns\": []}', '部分医院执行失败', '', '', '[]', '', '', 0, '', '', 'failed', '2026-05-18 14:42:41', 0.7, '[\"HOS_002\", \"HOS_001\"]', NULL, NULL, 'discharge', 1, '[{\"error\": null, \"status\": \"failed\", \"preview_data\": [{\"年龄\": 16, \"出生日期\": \"2009-08-15 00:00:00\", \"就诊时间\": \"2026-04-02 14:15:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z30.0\", \"诊断名称\": \"一般避孕咨询\", \"挂号流水号\": \"RG_RISK_002\", \"门急诊编号\": \"MZ20260402002\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 16, \"出生日期\": \"2010-03-10 00:00:00\", \"就诊时间\": \"2026-04-05 16:40:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_004\", \"门急诊编号\": \"MZ20260405004\", \"就诊科室名称\": \"呼吸内科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 17, \"出生日期\": \"2008-12-01 00:00:00\", \"就诊时间\": \"2026-04-10 11:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A51.9\", \"诊断名称\": \"早期梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_006\", \"门急诊编号\": \"MZ20260410006\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 14, \"出生日期\": \"2011-06-30 00:00:00\", \"就诊时间\": \"2026-04-15 23:10:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_008\", \"门急诊编号\": \"MZ20260415008\", \"就诊科室名称\": \"急诊科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 13, \"出生日期\": \"2013-01-25 00:00:00\", \"就诊时间\": \"2026-04-20 13:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ultrasound\", \"挂号流水号\": \"RG_RISK_010\", \"门急诊编号\": \"MZ20260420010\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}], \"hospital_code\": \"HOS_002\", \"hospital_name\": \"三亚市人民医院\", \"ratio_percent\": null, \"numerator_count\": 5, \"denominator_count\": null, \"denominator_preview_data\": []}, {\"error\": null, \"status\": \"failed\", \"preview_data\": [{\"年龄\": 13, \"出生日期\": \"2012-05-20 00:00:00\", \"就诊时间\": \"2026-04-01 09:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ultrasound\", \"挂号流水号\": \"RG_RISK_001\", \"门急诊编号\": \"MZ20260401001\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 7, \"出生日期\": \"2018-11-02 00:00:00\", \"就诊时间\": \"2026-04-03 10:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"A50.9\", \"诊断名称\": \"先天梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_003\", \"门急诊编号\": \"MZ20260403003\", \"就诊科室名称\": \"感染科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 11, \"出生日期\": \"2014-07-22 00:00:00\", \"就诊时间\": \"2026-04-08 08:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_005\", \"门急诊编号\": \"MZ20260408005\", \"就诊科室名称\": \"泌尿外科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 7, \"出生日期\": \"2019-02-14 00:00:00\", \"就诊时间\": \"2026-04-12 15:20:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_007\", \"门急诊编号\": \"MZ20260412007\", \"就诊科室名称\": \"儿科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 10, \"出生日期\": \"2015-09-09 00:00:00\", \"就诊时间\": \"2026-04-18 09:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_009\", \"门急诊编号\": \"MZ20260418009\", \"就诊科室名称\": \"泌尿外科\", \"患者去向名称\": \"回家\"}], \"hospital_code\": \"HOS_001\", \"hospital_name\": \"海南省示范医院\", \"ratio_percent\": null, \"numerator_count\": 5, \"denominator_count\": null, \"denominator_preview_data\": []}]');
INSERT INTO `indicator_execution` VALUES (195, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"14:42:50\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"14:42:50\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分子：0 条\"}, {\"time\": \"14:42:50\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分母：None 条\"}, {\"time\": \"14:42:50\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"14:42:50\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分子：2 条\"}, {\"time\": \"14:42:50\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分母：None 条\"}, {\"time\": \"14:42:50\", \"level\": \"info\", \"message\": \"汇总执行完成。总体指标值：None%（2/0）\"}]', 'WITH \n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\nmain_diag_sub AS (\n    SELECT \n        MDC_ORG_CD,\n        MDC_ORG_NM,\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\n        AND DIAG_CD IS NOT NULL\n        AND DIAG_CD != \'\'\n)\n-- 按医疗机构分组，统计不同亚目数量\nSELECT \n    MDC_ORG_CD AS \'医疗机构代码\',\n    MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\nFROM main_diag_sub\nWHERE sub_category IS NOT NULL \n    AND sub_category != \'\'\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\nORDER BY MDC_ORG_CD;', '', '', 2, 0, NULL, '', '', '{\"rows\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}', '{\"rows\": [], \"columns\": []}', '部分医院执行失败', '', '', '[]', '', '', 0, '', '', 'failed', '2026-05-18 14:42:50', 0.506, '[\"HOS_002\", \"HOS_001\"]', NULL, NULL, 'discharge', 1, '[{\"error\": null, \"status\": \"failed\", \"preview_data\": [], \"hospital_code\": \"HOS_002\", \"hospital_name\": \"三亚市人民医院\", \"ratio_percent\": null, \"numerator_count\": 0, \"denominator_count\": null, \"denominator_preview_data\": []}, {\"error\": null, \"status\": \"failed\", \"preview_data\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"hospital_code\": \"HOS_001\", \"hospital_name\": \"海南省示范医院\", \"ratio_percent\": null, \"numerator_count\": 2, \"denominator_count\": null, \"denominator_preview_data\": []}]');
INSERT INTO `indicator_execution` VALUES (196, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"14:46:50\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"14:46:50\", \"level\": \"info\", \"message\": \"分子结果：3 条记录。\"}, {\"time\": \"14:46:50\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"14:46:50\", \"level\": \"info\", \"message\": \"分母结果：10010 条记录。\"}, {\"time\": \"14:46:50\", \"level\": \"info\", \"message\": \"执行完成。指标值：0.03%（3/10010）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\';', '', 3, 10010, 0.03, '3/10010=0.03%', '', '{\"rows\": [{\"prm_key\": \"HMPG_20260405_04\", \"inhos_no\": \"INH_20260405_004\", \"admn_dt_tm\": \"2026-04-04 11:00:00\", \"dscg_dt_tm\": null, \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-04 12