INSERT INTO `indicator_execution` VALUES (198, 52, '主要手术ICD-9-CM-3四位码种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"14:47:11\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"14:47:11\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分子：None 条\"}, {\"time\": \"14:47:11\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分母：None 条\"}, {\"time\": \"14:47:11\", \"level\": \"error\", \"message\": \"[三亚市人民医院] 分子执行出错：(1054, \\\"Unknown column \'ms.mdc_org_cd\' in \'where clause\'\\\")\"}, {\"time\": \"14:47:11\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"14:47:11\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分子：None 条\"}, {\"time\": \"14:47:11\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分母：None 条\"}, {\"time\": \"14:47:11\", \"level\": \"error\", \"message\": \"[海南省示范医院] 分子执行出错：(1054, \\\"Unknown column \'ms.mdc_org_cd\' in \'where clause\'\\\")\"}, {\"time\": \"14:47:11\", \"level\": \"info\", \"message\": \"汇总执行完成。总体指标值：None%（0/0）\"}]', 'WITH \nmain_surgery AS (\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\n    SELECT \n        s.INHOS_NO,\n        s.OPRT_CD,\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\n    FROM FACT_MDC_RCD_HMPG_OPRT s\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\n        AND s.OPRT_CD IS NOT NULL\n        AND s.OPRT_CD != \'\'\n)\nSELECT \n    h.MDC_ORG_CD AS \'医疗机构代码\',\n    h.MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\nFROM main_surgery ms\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\nWHERE ms.surgery_4code IS NOT NULL \n    AND ms.surgery_4code != \'\'\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\nORDER BY h.MDC_ORG_CD;', '', '', 0, 0, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '部分医院执行失败', '', '', '[]', '', '', 0, '', '', 'failed', '2026-05-18 14:47:12', 0.599, '[\"HOS_002\", \"HOS_001\"]', NULL, NULL, 'discharge', 1, '[{\"error\": \"(1054, \\\"Unk