INSERT INTO `indicator_execution` VALUES (212, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'monthly', '2026年4月', 'ratio', 'SQL录入', '', '[{\"time\": \"15:40:21\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"15:40:22\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分子：0 条\"}, {\"time\": \"15:40:22\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分母：832 条\"}, {\"time\": \"15:40:22\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 指标值：0.0%\"}, {\"time\": \"15:40:22\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"15:40:23\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分子：1 条\"}, {\"time\": \"15:40:23\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分母：835 条\"}, {\"time\": \"15:40:23\", \"level\": \"info\", \"message\": \"[海南省示范医院] 指标值：0.1198%\"}, {\"time\": \"15:40:23\", \"level\": \"info\", \"message\": \"汇总执行完成。总体指标值：0.06%（1/1667）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\'  AND t1.MDC_ORG_CD IN (\'HOS_002\',\'HOS_001\') AND DATE(dscg_dt_tm) BETWEEN \'2026-04-01\' AND \'2026-04-30\'', '', 1, 1667, 0.06, '1/1667=0.06%', '', '{\"rows\": [{\"prm_key\": \"HMPG_20260405_06\", \"inhos_no\": \"INH_20260405_006\", \"admn_dt_tm\": \"2026-04-01 13:00:00\", \"dscg_dt_tm\": \"2026-04-06 14:00:00\", \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-01 14:15:00\"}], \"columns\": [\"prm_key\", \"inhos_no\", \"mdc_org_cd\", \"mdc_org_nm\", \"admn_dt_tm\", \"ODR_OPN_DT_TM\", \"ODR_ITM_TP_NM\", \"dscg_dt_tm\"]}', '{\"rows\": [{\"住院号\": \"INH_20260517_000011\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-24 22:40:00\", \"出院日期时间\": \"2026-04-03 02:40:00\"}, {\"住院号\": \"INH_20260517_000012\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-27 11:06:00\", \"出院日期时间\": \"2026-04-28 23:47:00\"}, {\"住院号\": \"INH_20260517_000017\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-13 16:52:00\", \"出院日期时间\": \"2026-04-18 23:53:00\"}, {\"住院号\": \"INH_20260517_000019\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-23 23:23:00\", \"出院日期时间\": \"2026-04-24 01:08:00\"}, {\"住院号\": \"INH_20260517_000032\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-11 00:34:00\", \"出院日期时间\": \"2026-04-23 01:07:00\"}, {\"住院号\": \"INH_20260517_000036\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-09 12:56:00\", \"出院日期时间\": \"2026-04-12 03:03:00\"}, {\"住院号\": \"INH_20260517_000045\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-09 13:14:00\", \"出院日期时间\": \"2026-04-17 17:07:00\"}, {\"住院号\": \"INH_20260517_000055\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-22 05:46:00\", \"出院日期时间\": \"2026-04-25 09:30:00\"}, {\"住院号\": \"INH_20260517_000090\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\"