, \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-08 05:57:00\", \"出院日期时间\": \"2026-01-10 14:42:00\"}, {\"住院号\": \"INH_20260517_000075\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-24 12:09:00\", \"出院日期时间\": \"2026-02-28 19:16:00\"}, {\"住院号\": \"INH_20260517_000076\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-30 02:39:00\", \"出院日期时间\": \"2026-03-31 02:29:00\"}, {\"住院号\": \"INH_20260517_000077\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-03 06:07:00\", \"出院日期时间\": \"2026-01-16 16:04:00\"}, {\"住院号\": \"INH_20260517_000078\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-18 01:22:00\", \"出院日期时间\": \"2026-01-28 03:47:00\"}, {\"住院号\": \"INH_20260517_000081\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-13 13:13:00\", \"出院日期时间\": \"2026-02-20 11:10:00\"}, {\"住院号\": \"INH_20260517_000085\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-05 01:07:00\", \"出院日期时间\": \"2026-03-12 17:25:00\"}, {\"住院号\": \"INH_20260517_000087\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2025-12-30 01:05:00\", \"出院日期时间\": \"2026-01-03 21:47:00\"}, {\"住院号\": \"INH_20260517_000088\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-20 17:35:00\", \"出院日期时间\": \"2026-02-02 10:34:00\"}, {\"住院号\": \"INH_20260517_000091\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-27 23:57:00\", \"出院日期时间\": \"2026-02-10 15:32:00\"}, {\"住院号\": \"INH_20260517_000092\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-19 20:43:00\", \"出院日期时间\": \"2026-02-22 12:09:00\"}, {\"住院号\": \"INH_20260517_000094\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-28 02:35:00\", \"出院日期时间\": \"2026-02-08 18:41:00\"}, {\"住院号\": \"INH_20260517_000096\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-24 02:40:00\", \"出院日期时间\": \"2026-03-25 01:18:00\"}, {\"住院号\": \"INH_20260517_000098\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-23 02:36:00\", \"出院日期时间\": \"2026-02-03 17:33:00\"}, {\"住院号\": \"INH_20260517_000099\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-07 10:58:00\", \"出院日期时间\": \"2026-03-16 20:35:00\"}, {\"住院号\": \"INH_20260517_000104\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-01-21 08:55:00\", \"出院日期时间\": \"2026-01-29 15:48:00\"}, {\"住院号\": \"INH_20260517_000105\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-24 14:01:00\", \"出院日期时间\": \"2026-03-29 14:01:00\"}], \"columns\": [\"住院号\", \"机构代码\", \"机构名称\", \"入院日期时间\", \"出院日期时间\"]}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    MDC_ORG_CD,    \\n    MDC_ORG_NM,    \\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM,\\n    DSCG_DT_TM\\nFROM (\\n    SELECT\\n        t1.DSCG_DT_TM,\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1;\", \"count\": 3, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-18 15:54:16', 0.598, '[]', 'quarterly', '2026-Q1', 'discharge', 0, '[]');
INSERT INTO `indicator_execution` VALUES (216, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"17:07:46\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"17:07:47\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分子：0 条\"}, {\"time\": \"17:07:47\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分母：4963 条\"}, {\"time\": \"17:07:47\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 指标值：0.0%\"}, {\"time\": \"17:07:47\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"17:07:47\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分子：3 条\"}, {\"time\": \"17:07:47\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分母：5047 条\"}, {\"time\": \"17:07:47\", \"level\": \"info\", \"message\": \"[海南省示范医院] 指标值：0.0594%\"}, {\"time\": \"17:07:47\", \"level\": \"info\", \"message\": \"汇总执行完成。总体指标值：0.03%（3/10010）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\'  AND t1.MDC_ORG_CD IN (\'HOS_002\',\'HOS_001\')', '', 3, 10010, 0.03, '3/10010=0.03%', '', '{\"rows\": [{\"prm_key\": \"HMPG_20260405_04\", \"inhos_no\": \"INH_20260405_004\", \"admn_dt_tm\": \"2026-04-04 11:00:00\", \"dscg_dt_tm\": null, \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-04 12:15:00\"}, {\"prm_key\": \"HMPG_20260405_06\", \"inhos_no\": \"INH_20260405_006\", \"admn_dt_tm\": \"2026-04-01 13:00:00\", \"dscg_dt_tm\": \"2026-04-06 14:00:00\", \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-01 14:15:00\"}, {\"prm_key\": \"HMPG_20260405_08\", \"inhos_no\": \"INH_20260405_008\", \"admn_dt_tm\": \"2026-04-03 15:00:00\", \"dscg_dt_tm\": null, \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\": \"2026-04-03 16:15:00\"}], \"columns\": [\"prm_key\", \"inhos_no\", \"mdc_org_cd\", \"mdc_org_nm\", \"admn_dt_tm\", \"ODR_OPN_DT_TM\", \"ODR_ITM_TP_NM\", \"dscg_dt_tm\"]}', '{\"rows\": [{\"住院号\": \"INH_20260517_000002\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-01 02:17:00\", \"出院日期时间\": \"2026-03-04 18:31:00\"}, {\"住院号\": \"INH_20260517_000003\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-28 06:36:00\", \"出院日期时间\": \"2026-03-31 22:14:00\"}, {\"住院号\": \"INH_20260517_000005\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-03 10:24:00\", \"出院日期时间\": \"2026-02-15 13:37:00\"}, {\"住院号\": \"INH_20260517_000006\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-18 13:17:00\", \"出院日期时间\": \"2026-03-03 04:28:00\"}, {\"住院号\": \"INH_20260517_000007\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-10 19:55:00\", \"出院日期时间\": \"2026-03-13 02:56:00\"}, {\"住院号\": \"INH_20260517_000010\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入