INSERT INTO `indicator_execution` VALUES (224, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'monthly', '2026年1月', 'ratio', 'SQL录入', '', '[{\"time\": \"21:29:57\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"21:29:57\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分子：0 条\"}, {\"time\": \"21:29:57\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分母：870 条\"}, {\"time\": \"21:29:57\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 指标值：0.0%\"}, {\"time\": \"21:29:57\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"21:29:58\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分子：0 条\"}, {\"time\": \"21:29:58\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分母：934 条\"}, {\"time\": \"21:29:58\", \"level\": \"info\", \"message\": \"[海南省示范医院] 指标值：0.0%\"}, {\"time\": \"21:29:58\", \"level\": \"info\", \"message\": \"汇总执行完成。总体指标值：0.0%（0/1804）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\'  AND t1.MDC_ORG_CD IN (\'HOS_002\',\'HOS_001\') AND DATE(dscg_dt_tm) BETWEEN \'2026-01-01\' AND \'2026-01-31\'', '', 0, 1804, 0, '0/1804=0.0%', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [{\"住院号\": \"INH_20260517_000020\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-03 18:30:00\", \"出院日期时间\": \"2026-01-08 21:36:00\"}, {\"住院号\": \"INH_20260517_000021\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-22 03:44:00\", \"出院日期时间\": \"2026-01-27 05:19:00\"}, {\"住院号\": \"INH_20260517_000024\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-24 21:33:00\", \"出院日期时间\": \"2026-01-27 01:56:00\"}, {\"住院号\": \"INH_20260517_000050\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-27 23:00:00\", \"出院日期时间\": \"2026-01-29 11:11:00\"}, {\"住院号\": \"INH_20260517_000073\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-08 05:57:00\", \"出院日期时间\": \"2026-01-10 14:42:00\"}, {\"住院号\": \"INH_20260517_000077\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-03 06:07:00\", \"出院日期时间\": \"2026-01-16 16:04:00\"}, {\"住院号\": \"INH_20260517_000078\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-18 01:22:00\", \"出院日期时间\": \"2026-01-28 03:47:00\"}, {\"住院号\": \"INH_20260517_000087\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2025-12-30 01:05:00\", \"出院日期时间\": \"2026-01-03 21:47:00\"}, {\"住院号\": \"INH_20260517_000107\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-07 20:11:00\", \"出院日期时间\": \"2026-01-13 02:29:00\"}, {\"住院号\": \"INH_20260517_000130\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2025-12-25 05:51:00\", \"出院日期时间\": \"2026-01-02 00:36:00\"}], \"columns\": [\"住院号\", \"机构代码\", \"机构名称\", \"入院日期时间\", \"出院日期时间\"]}', '', '', '', '[]', '', '', 0, '', '', 'success', '2026-05-18 21:29:58', 1.224, '[\"HOS_002\", \"HOS_001\"]', 'monthly', '2026-01'