OS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-01 08:30:00\", \"出院日期时间\": \"2026-04-05 10:00:00\"}, {\"住院号\": \"INH_20260405_002\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-02 09:30:00\", \"出院日期时间\": \"2026-04-04 14:00:00\"}, {\"住院号\": \"INH_20260405_003\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-03 10:30:00\", \"出院日期时间\": \"2026-04-08 09:00:00\"}, {\"住院号\": \"INH_20260405_004\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-04 11:30:00\", \"出院日期时间\": \"2026-04-10 16:00:00\"}, {\"住院号\": \"INH_20260405_005\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-05 12:30:00\", \"出院日期时间\": \"2026-04-06 11:00:00\"}, {\"住院号\": \"INH_20260405_006\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-01 13:30:00\", \"出院日期时间\": \"2026-04-07 10:00:00\"}, {\"住院号\": \"INH_20260405_007\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-02 14:30:00\", \"出院日期时间\": \"2026-04-09 15:00:00\"}, {\"住院号\": \"INH_20260405_008\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-03 15:30:00\", \"出院日期时间\": \"2026-04-04 09:00:00\"}, {\"住院号\": \"INH_20260405_009\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-04 16:30:00\", \"出院日期时间\": \"2026-04-11 14:00:00\"}, {\"住院号\": \"INH_20260405_010\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-05 17:30:00\", \"出院日期时间\": \"2026-04-08 10:00:00\"}]}, {\"error\": null, \"status\": \"success\", \"preview_data\": [], \"hospital_code\": \"HOS_002\", \"hospital_name\": \"三亚市人民医院\", \"ratio_percent\": 0.0, \"numerator_count\": 0, \"denominator_count\": 4963, \"denominator_preview_data\": [{\"住院号\": \"INH_20260517_000002\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-01 02:17:00\", \"出院日期时间\": \"2026-03-04 18:31:00\"}, {\"住院号\": \"INH_20260517_000003\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-28 06:36:00\", \"出院日期时间\": \"2026-03-31 22:14:00\"}, {\"住院号\": \"INH_20260517_000005\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-03 10:24:00\", \"出院日期时间\": \"2026-02-15 13:37:00\"}, {\"住院号\": \"INH_20260517_000006\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-18 13:17:00\", \"出院日期时间\": \"2026-03-03 04:28:00\"}, {\"住院号\": \"INH_20260517_000007\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-10 19:55:00\", \"出院日期时间\": \"2026-03-13 02:56:00\"}, {\"住院号\": \"INH_20260517_000010\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2025-12-08 01:38:00\", \"出院日期时间\": \"2025-12-09 04:56:00\"}, {\"住院号\": \"INH_20260517_000011\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-24 22:40:00\", \"出院日期时间\": \"2026-04-03 02:40:00\"}, {\"住院号\": \"INH_20260517_000012\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-27 11:06:00\", \"出院日期时间\": \"2026-04-28 23:47:00\"}, {\"住院号\": \"INH_20260517_000015\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2025-12-07 00:20:00\", \"出院日期时间\": \"2025-12-18 10:06:00\"}, {\"住院号\": \"INH_20260517_000016\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-01 16:08:00\", \"出院日期时间\": \"2026-03-12 23:46:00\"}]}]');
INSERT INTO `indicator_execution` VALUES (232, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"13:17:19\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"13:17:20\", \"level\": \"info\", \"message\": \"[海南省示范医院] 查询结果：2 条记录。\"}, {\"time\": \"13:17:20\", \"level\": \"info\", \"message\": \"[海南省示范医院] 执行完成，共 2 人次。\"}, {\"time\": \"13:17:20\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"13:17:20\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 查询结果：0 条记录。\"}, {\"time\": \"13:17:20\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 执行完成，共 0 人次。\"}, {\"time\": \"13:17:20\", \"level\": \"info\", \"message\": \"汇总执行完成，共 2 人次。\"}]', '', '', 'WITH \n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\nmain_diag_sub AS (\n    SELECT \n        MDC_ORG_CD,\n        MDC_ORG_NM,\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\n        AND DIAG_CD IS NOT NULL\n        AND DIAG_CD != \'\'\n)\n-- 按医疗机构分组，统计不同亚目数量\nSELECT \n    MDC_ORG_CD AS \'医疗机构代码\',\n    MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\nFROM main_diag_sub\nWHERE sub_category IS NOT NULL \n    AND sub_category != \'\'\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\nORDER BY MDC_ORG_CD;', 2, NULL, NULL, '', '', '{\"rows\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[]', '', '', 0, '', '', 'success', '2026-05-19 13:17:20', 0.475, '[]', NULL, NULL, 'discharge', 1, '[{\"count\": 2, \"error\": null, \"status\": \"success\", \"preview_data\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"hospital_code\": \"HOS_001\", \"hospital_name\": \"海南省示范医院\", \"numerator_count\": 2, \"preview_columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}, {\"count\": 0, \"error\": null, \"status\": \"success\", \"preview_data\": [], \"hospital_code\": \"HOS_002\", \"hospital_name\": \"三亚市人民医院\", \"numerator_count\": 0, \"preview_columns\": []}]');
INSERT INTO `indicator_execution` VALUES (233, 10, '未成年人高危预警', 'manual', 'four', 'immediate', '全量', 'count', 'SQL录入', '审核范围：未成年人', '[{\"time\": \"13:17:31\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"13:17:31\", \"level\": \"info\", \"message\": \"[海南省示范医院] 查询结果：5 条记录。\"}, {\"time\": \"13:17:31\", \"level\": \"info\", \"message\": \"[海南省示范医院] 执行完成，共 5 人次。\"}, {\"time\": \"13:17:31\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"13:17:31\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 查询结果：5 条记录。\"}, {\"time\": \"13:17:31\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 执行完成，共 5 人次。\"}, {\"time\": \"13:17:31\", \"level\": \"info\", \"message\": \"汇总执行完成，共 10 人次。\"}]', '', '', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        -- 时间限制（用的月份）\n        AND SUBSTR(v.VST_DT_TM, 1, 7) = \'2026-04\' \n        /* \n        也可以用“日”来筛选\n        AND v.VST_DT_TM >= \'2026-04-01 00:00:00\'\n        AND v.VST_DT_TM <  \'2026-05-01 00:00:00\'\n        */\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \n        -- 年龄筛选\n        /*\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\n        */\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18;', 10, NULL, NULL, '', '', '{\"rows\": [{\"年龄\": 13, \"出生日期\": \"2012-05-20 00:00:00\", \"就诊时间\": \"2026-04-01 09:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ultrasound\", \"挂号流水号\": \"RG_RISK_001\", \"门急诊编号\": \"MZ20260401001\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 7, \"出生日期\": \"2018-11-02 00:00:00\", \"就诊时间\": \"2026-04-03 10:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"A50.9\", \"诊断名称\": \"先天梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_003\", \"门急诊编号\": \"MZ20260403003\", \"就诊科室名称\": \"感染科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 11, \"出生日期\": \"2014-07-22 00:00:00\", \"就诊时间\": \"2026-04-08 08:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_005\", \"门急诊编号\": \"MZ20260408005\", \"就诊科室名称\": \"泌尿外科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 7, \"出生日期\": \"2019-02-14 00:00:00\", \"就诊时间\": \"2026-04-12 15:20:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_007\", \"门急诊编号\": \"MZ20260412007\", \"就诊科室名称\": \"儿科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 10, \"出生日期\": \"2015-09-09 00:00:00\", \"就诊时间\": \"2026-04-18 09:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\",