2026-03-26 16:34:00\", \"出院日期时间\": \"2026-04-07 06:54:00\"}, {\"住院号\": \"INH_20260517_000144\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-11 13:15:00\", \"出院日期时间\": \"2026-04-20 03:53:00\"}, {\"住院号\": \"INH_20260517_000145\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-18 13:20:00\", \"出院日期时间\": \"2026-04-19 00:02:00\"}, {\"住院号\": \"INH_20260517_000147\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-23 11:24:00\", \"出院日期时间\": \"2026-04-02 22:51:00\"}, {\"住院号\": \"INH_20260517_000156\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-14 03:12:00\", \"出院日期时间\": \"2026-04-24 10:19:00\"}, {\"住院号\": \"INH_20260517_000161\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-10 11:42:00\", \"出院日期时间\": \"2026-04-12 11:58:00\"}, {\"住院号\": \"INH_20260517_000164\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-30 20:28:00\", \"出院日期时间\": \"2026-04-11 13:20:00\"}, {\"住院号\": \"INH_20260517_000173\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-19 08:16:00\", \"出院日期时间\": \"2026-04-24 16:28:00\"}, {\"住院号\": \"INH_20260517_000183\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-17 18:16:00\", \"出院日期时间\": \"2026-04-19 17:13:00\"}, {\"住院号\": \"INH_20260517_000184\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-20 16:54:00\", \"出院日期时间\": \"2026-04-29 23:16:00\"}, {\"住院号\": \"INH_20260517_000189\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-31 04:08:00\", \"出院日期时间\": \"2026-04-03 06:00:00\"}, {\"住院号\": \"INH_20260517_000201\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-15 01:42:00\", \"出院日期时间\": \"2026-04-22 23:34:00\"}, {\"住院号\": \"INH_20260517_000202\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-16 01:52:00\", \"出院日期时间\": \"2026-04-19 02:08:00\"}, {\"住院号\": \"INH_20260517_000203\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-27 08:57:00\", \"出院日期时间\": \"2026-04-07 16:18:00\"}, {\"住院号\": \"INH_20260517_000211\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-24 02:06:00\", \"出院日期时间\": \"2026-04-28 19:17:00\"}, {\"住院号\": \"INH_20260517_000215\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-16 21:52:00\", \"出院日期时间\": \"2026-04-28 04:42:00\"}, {\"住院号\": \"INH_20260517_000230\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-08 12:54:00\", \"出院日期时间\": \"2026-04-09 07:32:00\"}], \"columns\": [\"住院号\", \"机构代码\", \"机构名称\", \"入院日期时间\", \"出院日期时间\"]}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    MDC_ORG_CD,    \\n    MDC_ORG_NM,    \\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM,\\n    DSCG_DT_TM\\nFROM (\\n    SELECT\\n        t1.DSCG_DT_TM,\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1;\", \"count\": 3, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-19 21:01:12', 0.557, '[]', 'monthly', '2026-04', 'discharge', 0, '[]');
INSERT INTO `indicator_execution` VALUES (276, 10, '未成年人高危预警', 'manual', 'four', 'immediate', '全量', 'count', 'SQL录入', '审核范围：未成年人', '[{\"time\": \"21:08:04\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"21:08:04\", \"level\": \"info\", \"message\": \"查询结果：10 条记录。\"}, {\"time\": \"21:08:04\", \"level\": \"info\", \"message\": \"执行完成，共 10 人次。\"}]', '', '', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \n        -- 年龄筛选\n        /*\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\n        */\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18;', NULL, NULL, NULL, '', '', '{\"rows\": [{\"年龄\": 13, \"出生日期\": \"2012-05-20 00:00:00\", \"就诊时间\": \"2026-04-01 09:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ultrasound\", \"挂号流水号\": \"RG_RISK_001\", \"门急诊编号\": \"MZ20260401001\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 16, \"出生日期\": \"2009-08-15 00:00:00\", \"就诊时间\": \"2026-04-02 14:15:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z30.0\", \"诊断名称\": \"一般避孕咨询\", \"挂号流水号\": \"RG_RISK_002\", \"门急诊编号\": \"MZ20260402002\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 7, \"出生日期\": \"2018-11-02 00:00:00\", \"就诊时间\": \"2026-04-03 10:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"A50.9\", \"诊断名称\": \"先天梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_003\", \"门急诊编号\": \"MZ20260403003\", \"就诊科室名称\": \"感染科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 16, \"出生日期\": \"2010-03-10 00:00:00\", \"就诊时间\": \"2026-04-05 16:40:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_004\", \"门急诊编号\": \"MZ20260405004\", \"就诊科室名称\": \"呼吸内科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 11, \"出生日期\": \"2014-07-22 00:00:00\", \"就诊时间\": \"2026-04-08 08:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG_RISK_005\", \"门急诊编号\": \"MZ20260408005\", \"就诊科室名称\": \"泌尿外科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 17, \"出生日期\": \"2008-12-01 00:00:00\", \"就诊时间\": \"2026-04-10 11:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A51.9\", \"诊断名称\": \"早期梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_006\", \"门急诊编号\": \"MZ20260410006\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 7, \"出生日期\": \"2019-02-14 00:00:00\", \"就诊时间\": \"2026-04-12 15:20:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"海南省示范医院\", \"诊断代码\": \"N39.0\", \"诊断名称\": \"未特指的泌尿道感染\", \"挂号流水号\": \"RG